func PerIPRateLimiter() gin.HandlerFunc {
    clients := sync.Map{}
    return func(c *gin.Context) {
        ip := c.ClientIP()
        val, _ := clients.LoadOrStore(ip, rate.NewLimiter(10, 20))
        limiter := val.(*rate.Limiter)
        if !limiter.Allow() {
            c.AbortWithStatusJSON(429, gin.H{"error": "rate limit exceeded"})
            return
        }
        c.Next()
    }
}

